//测试 deepseek

#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N = 1005;

int T, n;
ll a[N];
ll L[N][N], R[N][N];

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 1; i <= n; ++i) scanf("%lld", &a[i]);
        for (int i = 1; i <= n; ++i) L[i][i] = R[i][i] = a[i];
        for (int len = 2; len <= n; ++len) {
            for (int i = 1; i + len - 1 <= n; ++i) {
                int j = i + len - 1;
                // 计算 L[i][j]
                ll x = a[i];
                ll l1 = L[i+1][j], r1 = R[i+1][j];
                if (x == r1) L[i][j] = 0;
                else if (l1 <= x && x < r1) L[i][j] = x + 1;
                else if (r1 < x && x <= l1) L[i][j] = x - 1;
                else L[i][j] = x;
                // 计算 R[i][j]
                ll y = a[j];
                ll l2 = L[i][j-1], r2 = R[i][j-1];
                if (y == l2) R[i][j] = 0;
                else if (r2 <= y && y < l2) R[i][j] = y + 1;
                else if (l2 < y && y <= r2) R[i][j] = y - 1;
                else R[i][j] = y;
            }
        }
        printf("%d\n", L[1][n] != 0 ? 1 : 0);
    }
    return 0;
}
